const fs = require('fs');
const path = require('path');
const dir = 'c:/Users/veeramani/.gemini/antigravity/scratch/Automation Workflow/temp_results';
const files = fs.readdirSync(dir).filter(f => f.endsWith('.json'));

const results = files.map(f => JSON.parse(fs.readFileSync(path.join(dir, f))));
const passed = results.filter(r => r.status === 'passed').length;
const failed = results.filter(r => r.status === 'failed').length;

let html = `<table border="1"><tr><th>Test</th><th>Status</th><th>Duration</th></tr>`;
results.forEach(r => {
  html += `<tr><td>${r.filename}</td><td style="color:${r.status === 'passed' ? 'green' : 'red'}">${r.status}</td><td>${r.duration}</td></tr>`;
});
html += `</table>`;

return { json: { total: results.length, passed, failed, html } };
